import { useEffect, useMemo, useState } from 'react';
import { Link } from 'react-router-dom';
import AdminMentorLayout from '../components/AdminMentorLayout.jsx';
import { ErrorState, LoadingState } from '../components/LoadingState.jsx';
import StatusBadge from '../components/StatusBadge.jsx';
import { adminMentorApi } from '../services/api.js';
import { formatDateTime } from '../utils/formatters.js';

export default function ReviewQueuePage() {
  const [submissions, setSubmissions] = useState([]);
  const [filters, setFilters] = useState({ search: '', courseId: 'ALL' });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    let mounted = true;

    setLoading(true);
    adminMentorApi
      .getMentorReviewQueue(filters)
      .then((response) => {
        if (mounted) {
          setSubmissions(response.data);
          setError('');
        }
      })
      .catch((requestError) => {
        if (mounted) {
          setError(requestError.message);
        }
      })
      .finally(() => {
        if (mounted) {
          setLoading(false);
        }
      });

    return () => {
      mounted = false;
    };
  }, [filters]);

  const courseOptions = useMemo(() => {
    const uniqueCourses = new Map();
    submissions.forEach((submission) => {
      uniqueCourses.set(submission.courseId, submission.courseTitle);
    });
    return Array.from(uniqueCourses.entries()).map(([courseId, courseTitle]) => ({ courseId, courseTitle }));
  }, [submissions]);

  const updateFilter = (fieldName, value) => {
    setFilters((current) => ({ ...current, [fieldName]: value }));
  };

  return (
    <AdminMentorLayout
      area="mentor"
      title="Review Queue"
      subtitle="Danh sach final project dang PENDING va thuoc course mentor duoc assign."
    >
      <div className="card admin-mentor-card mb-4">
        <div className="card-body">
          <div className="row g-3 align-items-end">
            <div className="col-12 col-lg-7">
              <label className="form-label" htmlFor="mentor-queue-search">
                Search
              </label>
              <input
                className="form-control"
                id="mentor-queue-search"
                onChange={(event) => updateFilter('search', event.target.value)}
                placeholder="Search learner or course"
                type="search"
                value={filters.search}
              />
            </div>
            <div className="col-12 col-lg-4">
              <label className="form-label" htmlFor="mentor-queue-course">
                Course
              </label>
              <select
                className="form-select"
                id="mentor-queue-course"
                onChange={(event) => updateFilter('courseId', event.target.value)}
                value={filters.courseId}
              >
                <option value="ALL">ALL</option>
                {courseOptions.map((course) => (
                  <option key={course.courseId} value={course.courseId}>
                    {course.courseTitle}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>
      </div>

      {loading ? <LoadingState message="Dang tai review queue..." /> : null}
      {!loading && error ? <ErrorState message={error} /> : null}

      {!loading ? (
        <div className="card admin-mentor-card">
          <div className="card-header bg-white d-flex justify-content-between align-items-center">
            <h2 className="h5 mb-0">Pending submissions</h2>
            <span className="badge text-bg-light border">{submissions.length} pending</span>
          </div>
          <div className="table-responsive">
            <table className="table table-hover align-middle mb-0 admin-mentor-table">
              <thead className="table-light">
                <tr>
                  <th>Learner</th>
                  <th>Course</th>
                  <th>Attempt</th>
                  <th>Submitted</th>
                  <th>Project</th>
                  <th>Status</th>
                  <th className="text-end">Action</th>
                </tr>
              </thead>
              <tbody>
                {submissions.map((submission) => (
                  <tr key={submission.id}>
                    <td>
                      <strong className="d-block">{submission.learnerName}</strong>
                      <span className="small text-secondary">{submission.learnerEmail}</span>
                    </td>
                    <td>{submission.courseTitle}</td>
                    <td>#{submission.attemptNo}</td>
                    <td>{formatDateTime(submission.submittedAt)}</td>
                    <td>
                      <a href={submission.projectUrl} rel="noreferrer" target="_blank">
                        Repository
                      </a>
                    </td>
                    <td>
                      <StatusBadge status={submission.status} />
                    </td>
                    <td className="text-end">
                      <Link className="btn btn-sm btn-primary" to={`/mentor/reviews/${submission.id}`}>
                        Review
                      </Link>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      ) : null}
    </AdminMentorLayout>
  );
}
